//#region src/controllers/util.ts
var INTERNAL_ERROR_MESSAGE = "服务器内部错误";
var UPSTREAM_ERROR_MESSAGE = "上游服务异常";
var setJsonResponse = (ctx, status, body) => {
	ctx.status = status;
	ctx.type = "application/json";
	ctx.body = body;
};
var isMissingRequiredValue = (value) => {
	if (value === void 0 || value === null) return true;
	if (typeof value === "string") return value.trim() === "";
	return false;
};
function createController(apiFunction, options) {
	return async (ctx, _next) => {
		const controllerName = options?.name || apiFunction.name || "anonymous";
		const duration = require_services.startTimer();
		require_services.logControllerStart(controllerName, ctx);
		try {
			const params = {
				...ctx.query,
				...ctx.params
			};
			if (options?.validator) {
				const validation = options.validator(params);
				if (!validation.valid) {
					setJsonResponse(ctx, 400, { response: validation.error || options.errorMessage || "Invalid parameters" });
					return;
				}
			}
			const { status, body } = await apiFunction(options?.buildApiOptions ? options.buildApiOptions(ctx, params) : {
				method: "get",
				params,
				option: {}
			});
			setJsonResponse(ctx, status, body);
			require_services.logControllerSuccess(controllerName, ctx, duration());
		} catch (error) {
			require_services.logControllerFailure(controllerName, error, duration());
			if (options?.onError) options.onError(ctx, error);
			else setJsonResponse(ctx, 500, { error: INTERNAL_ERROR_MESSAGE });
		}
	};
}
function validateRequired(fields) {
	return (params) => {
		const missingFields = fields.filter((field) => isMissingRequiredValue(params[field]));
		if (missingFields.length > 0) return {
			valid: false,
			error: `缺少必需参数：${missingFields.join(", ")}`
		};
		return { valid: true };
	};
}
function setApiResponse(ctx, apiResponse) {
	setJsonResponse(ctx, apiResponse.status || 500, apiResponse.body);
}
function withErrorHandler(handler, name = handler.name || "anonymous") {
	return async (ctx, next) => {
		const duration = require_services.startTimer();
		require_services.logControllerStart(name, ctx);
		try {
			await handler(ctx);
			require_services.logControllerSuccess(name, ctx, duration());
			await next();
		} catch (error) {
			require_services.logControllerFailure(name, error, duration());
			setJsonResponse(ctx, 502, { error: UPSTREAM_ERROR_MESSAGE });
		}
	};
}
